try {
  const workflowId = 'CWF-120';
  const defaultSkillMap = {
    'CWF-610': 'M-185',
    'CWF-620': 'M-200',
    'CWF-630': 'M-215'
  };
  const skillId = $json.skill_id || defaultSkillMap[workflowId] || 'M-001';
  const dossierId = $json.body?.dossier_id || $json.dossier_context?.dossier_id || $json.dossier_id || 'DOSSIER-UNSPECIFIED';

  const payload = {
    dossier_id: dossierId,
    dossier_ref: dossierId,
    workflow_id: workflowId,
    workflow_ref: workflowId,
    skill_id: skillId,
    source_node: 'Skill Execution Node',
    route_id: $json.body?.route_id || $json.route_id || $json.dossier_context?.route || null,
    task: $json.body?.topic || $json.body?.user_message || $json.body?.message || $json.topic || $json.user_message || $json.message || (($json.body?.mission_context || $json.mission_context) && (($json.body?.mission_context || $json.mission_context).normalized_topic || ($json.body?.mission_context || $json.mission_context).original_user_message)) || 'MISSION_CONTEXT_MISSING',
    context: {
      topic: $json.body?.topic || $json.body?.user_message || $json.body?.message || $json.topic || $json.user_message || $json.message || (($json.body?.mission_context || $json.mission_context) && (($json.body?.mission_context || $json.mission_context).normalized_topic || ($json.body?.mission_context || $json.mission_context).original_user_message)) || null,
      mode: $json.body?.user_mode || $json.user_mode || $json.mode || 'creator', mission_context: $json.body?.mission_context || $json.mission_context || null
    },
    dossier: typeof $json.dossier === 'object' ? $json.dossier : {}
  };

  const result = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://127.0.0.1:5002/operator/skill-runtime',
    headers: { 'content-type': 'application/json' },
    body: payload,
    json: true,
    timeout: 120000
  });
  if (result.status !== 'SUCCESS' || !result.runtime_packet) {
    throw new Error(String(result.error || 'skill-runtime returned no runtime_packet'));
  }

  return [{
    json: {
      ...$json,
      phase8_runtime_probe: {
        workflow_id: workflowId,
        skill_id: skillId,
        status: 'SUCCESS',
        had_error: false,
        error_message: '',
        timestamp: new Date().toISOString()
      },
      runtime_packet: result.runtime_packet,
      skill_execution_result: result.skill_execution_result || result,
      runtime: { had_error: false, error_message: '' }
    }
  }];
} catch (error) {
  const message = String(error && error.message ? error.message : error);
  return [{
    json: {
      ...$json,
      phase8_runtime_probe: {
        workflow_id: 'CWF-120',
        skill_id: $json.skill_id || null,
        status: 'ERROR',
        had_error: true,
        error_message: message,
        timestamp: new Date().toISOString()
      },
      runtime_packet: null,
      skill_execution_result: null,
      runtime: { had_error: true, error_message: message }
    }
  }];
}

try {
  const packet = $json.runtime_packet;
  if (!packet || !packet.instance_id || !packet.artifact_family || !packet.dossier_ref) {
    throw new Error('missing required runtime_packet fields');
  }
  return [{ json: { ...$json, validation_status: 'SUCCESS', route_to_error: false } }];
} catch (error) {
  return [{ json: { ...$json, validation_status: 'FAILED', route_to_error: true, validation_error: String(error.message || error) } }];
}

if ($json.route_to_error) return [];
return [{
  json: {
    ...$json,
    dossier_write: {
      mutation_type: 'append_to_array',
      target: 'dossier.runtime_packets',
      timestamp: new Date().toISOString(),
      writer_id: 'CWF-120',
      skill_id: 'CWF-120',
      instance_id: $json.runtime_packet.instance_id,
      schema_version: $json.runtime_packet.schema_version,
      lineage_reference: $json.runtime_packet.producer_workflow,
      audit_entry: 'append-only dossier write from canonical workflow'
    }
  }
}];

if ($json.route_to_error) return [];
return [{
  json: {
    ...$json,
    se_packet_index_write: {
      operation: 'create_new_index_row',
      packet_id: $json.runtime_packet.instance_id,
      dossier_id: $json.runtime_packet.dossier_ref,
      packet_family: $json.runtime_packet.artifact_family,
      workflow_id: 'CWF-120',
      created_at: new Date().toISOString()
    }
  }
}];

if (!$json.route_to_error) return [];
return [{
  json: {
    workflow_id: 'CWF-120',
    routing_decision: 'ERROR',
    route_to_workflow: 'WF-900',
    error_message: $json.validation_error || $json.runtime?.error_message || 'unknown workflow error',
    failure_packet: $json.runtime_packet || null
  }
}];

if ($json.route_to_error) return [];
let nextWorkflow = 'CWF-130';
let decision = 'SUCCESS_PATH';

if ('CWF-120' === 'CWF-140') {
  const confidence = Number($json.runtime_packet?.payload?.research_confidence_score ?? 1);
  if (confidence < 0.85) {
    nextWorkflow = 'CWF-140';
    decision = 'RUN_PHASE1C_CONDITIONAL_RESEARCH';
  } else {
    nextWorkflow = 'CWF-210';
    decision = 'SKIP_PHASE1C_PROCEED_SCRIPT';
  }
}

if ('CWF-120' === 'WF-020') {
  const approval = String($json.runtime_packet?.payload?.approval_decision || 'APPROVED');
  nextWorkflow = approval === 'APPROVED' ? 'WF-300' : 'WF-021';
  decision = approval === 'APPROVED' ? 'APPROVED_FOR_PUBLISHING' : 'REJECTED_ROUTE_REPLAY';
}

if ('CWF-120' === 'WF-021') {
  nextWorkflow = $json.replay_target_workflow || 'CWF-210';
  decision = 'REPLAY_TO_PRIOR_STAGE';
}

return [{
  json: {
    ...$json,
    routing_decision: {
      on_success_next_workflow: nextWorkflow,
      on_error_workflow: 'WF-900',
      decision,
      wf900_bound: true
    }
  }
}];

if ($json.route_to_error) return [];
return [{
  json: {
    workflow_id: 'CWF-120',
    execution_status: 'SUCCESS',
    completion_packet: {
      instance_id: 'CWF-120-COMP-' + Date.now(),
      artifact_family: 'workflow_completion_packet',
      schema_version: '1.0.0',
      producer_workflow: 'CWF-120',
      dossier_ref: $json.runtime_packet?.dossier_ref || 'DOSSIER-UNSPECIFIED',
      created_at: new Date().toISOString(),
      status: 'CREATED',
      payload: {
        source_packet_id: $json.runtime_packet?.instance_id || null,
        next_workflow: $json.routing_decision?.on_success_next_workflow || 'CWF-130',
        route_to_wf900: 'WF-900'
      }
    }
  }
}];
